import{_ as t,c as a,o as e,a4 as i}from"./chunks/framework.C7a7wY1S.js";const b=JSON.parse('{"title":"开发中遇到的各种场景","description":"","frontmatter":{},"headers":[],"relativePath":"project/web/scene.md","filePath":"project/web/scene.md","lastUpdated":1729676720000}'),l={name:"project/web/scene.md"},s=i('<h1 id="开发中遇到的各种场景" tabindex="-1">开发中遇到的各种场景 <a class="header-anchor" href="#开发中遇到的各种场景" aria-label="Permalink to &quot;开发中遇到的各种场景&quot;">​</a></h1><h2 id="_1-如何判断设备类型-手机端-移动端-ipad-并判断浏览器的类型" tabindex="-1">1.如何判断设备类型(手机端，移动端，ipad),并判断浏览器的类型 <a class="header-anchor" href="#_1-如何判断设备类型-手机端-移动端-ipad-并判断浏览器的类型" aria-label="Permalink to &quot;1.如何判断设备类型(手机端，移动端，ipad),并判断浏览器的类型&quot;">​</a></h2><p>在开发中经常会遇到不同的操作系统，不同的浏览器分别作出相应的操作，因此我们需要先判断出设备和浏览器的类型，以下是判断设备的浏览器类型的几种方法</p><h3 id="第一种-使用-user-agent-字符串" tabindex="-1">第一种：使用 User-Agent 字符串 <a class="header-anchor" href="#第一种-使用-user-agent-字符串" aria-label="Permalink to &quot;第一种：使用 User-Agent 字符串&quot;">​</a></h3><p>不同的浏览器和设备都会有不同的特征，而这些特征可以通过navigator.userAgent这个属性获取，这个属性包含了浏览器的版本，操作系统等信息，通过解析这个信息，我们可以 识别出大多数的浏览器和设备类型</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"></span></code></pre></div><h3 id="第二种-通过比较屏幕的宽度判断设备类型-不建议使用" tabindex="-1">第二种: 通过比较屏幕的宽度判断设备类型 (不建议使用) <a class="header-anchor" href="#第二种-通过比较屏幕的宽度判断设备类型-不建议使用" aria-label="Permalink to &quot;第二种: 通过比较屏幕的宽度判断设备类型 (不建议使用)&quot;">​</a></h3><h2 id="_2-单点登录如何实现" tabindex="-1">2.单点登录如何实现 <a class="header-anchor" href="#_2-单点登录如何实现" aria-label="Permalink to &quot;2.单点登录如何实现&quot;">​</a></h2><h2 id="_3-跑马灯如何实现" tabindex="-1">3.跑马灯如何实现 <a class="header-anchor" href="#_3-跑马灯如何实现" aria-label="Permalink to &quot;3.跑马灯如何实现&quot;">​</a></h2><h2 id="_4-等高的瀑布流和不等高的瀑布流如何实现" tabindex="-1">4.等高的瀑布流和不等高的瀑布流如何实现 <a class="header-anchor" href="#_4-等高的瀑布流和不等高的瀑布流如何实现" aria-label="Permalink to &quot;4.等高的瀑布流和不等高的瀑布流如何实现&quot;">​</a></h2><h2 id="_5-扫码登陆的流程" tabindex="-1">5.扫码登陆的流程 <a class="header-anchor" href="#_5-扫码登陆的流程" aria-label="Permalink to &quot;5.扫码登陆的流程&quot;">​</a></h2><h2 id="_6-在邮件中制作html" tabindex="-1">6.在邮件中制作html <a class="header-anchor" href="#_6-在邮件中制作html" aria-label="Permalink to &quot;6.在邮件中制作html&quot;">​</a></h2><p>有很多公司都会在邮件中给自家的用户发送邮件进行沟通或者营销推广，但是在邮件中，由于为了安全，会过滤掉很多东西，例如js,css中的定位，浮动等等。 以下是邮件html的一些注意点：</p><ol><li>不支持js，js在所有的邮件系统中都会被过滤掉，所以不要写js</li><li>整体的布局使用table，布局不能使用弹性盒(flex),定位(position),少用浮动(float),清除浮动可以使用下列代码,可以使用display:inline-block</li></ol><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">table</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> style</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;clear:both&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">table</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><ol start="3"><li>图片是唯一可以引用的外部资源。其他的外部资源，比如样式表文件、字体文件、视频文件等，一概不能引用。并且会过滤掉style标签，所以所有的css都要写成内联样式</li><li>图片要指定宽高，不少客户端默认不显示图片（比如Gmail），所以要确保即使没有图片，主要内容也能被阅读,主要的布局也能正常显示。</li><li>背景图片不能使用background-image,image会被过滤掉，但是可以使用background来代替，但是功能有限</li><li>如果 td 和 td 之间有间隔，使用<code>&lt;td style=&quot;border-bottom:10px solid #fff&quot;&gt;&lt;/td&gt;</code>，这样写的话 td 之间是不会有间隔的。使用<code>&lt;td style=&quot;margin-bottom: 10px&quot;&gt;&lt;/td&gt;</code>也是不会有空格的。如果 td 之间有间隙，必须用<code>&lt;td&gt;&lt;/td&gt;&lt;td height=&quot;10px&quot;&gt; &lt;/td&gt;&lt;td&gt;&lt;/td&gt;</code>来隔开。但是如果是 table，则<code>&lt;table style=&quot;border-top:10px solid #ffffff; border-bottom:20px solid #ffffff&quot;&gt;&lt;/table&gt;</code>里面的内容会在上下有空行。</li><li>font-family属性不能为空，否则会被QQ屏蔽为垃圾邮件。</li><li>若邮件模板内侧边或者上下有空白间距，不要用 padding，必须得用标准的 td 来设定空白间距，否则会导致各个邮箱解析不同。</li></ol><h3 id="总的来说-邮件中的html-标签和属性能解决的样式决不使用-css-样式。" tabindex="-1">总的来说，邮件中的html 标签和属性能解决的样式决不使用 CSS 样式。 <a class="header-anchor" href="#总的来说-邮件中的html-标签和属性能解决的样式决不使用-css-样式。" aria-label="Permalink to &quot;总的来说，邮件中的html 标签和属性能解决的样式决不使用 CSS 样式。&quot;">​</a></h3>',17),o=[s];function h(d,r,n,c,p,u){return e(),a("div",null,o)}const k=t(l,[["render",h]]);export{b as __pageData,k as default};
